#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        printf("%d",N);
        for(int i=1;i<N;i++) printf(" %d",i);
        if(T) printf("\n");
    }
    return 0;
}

